import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as r,c as i,a}from"./app-4a161474.js";const l={},t=a('<h2 id="文章内容" tabindex="-1"><a class="header-anchor" href="#文章内容" aria-hidden="true">#</a> 文章内容</h2><ul><li>六王毕，四海⼀，蜀⼭⺎，阿房出。覆压三百余⾥，隔离天⽇。骊⼭北构⽽⻄折，直⾛咸阳。⼆ 川溶溶，流⼊宫墙。五步⼀楼，⼗步⼀阁；廊腰缦回，檐⽛⾼啄；各抱地势，钩⼼⽃⻆。盘盘焉，囷<br> 囷焉，蜂房⽔涡，矗不知其⼏千万落。⻓桥卧波，未云何⻰？复道⾏空，不霁何虹？⾼低冥迷，不知<br> ⻄东。歌台暖响，春光融融；舞殿冷袖，⻛⾬凄凄。⼀⽇之内，⼀宫之间，⽽⽓候不⻬。(不知其 ⼀ 作：不知乎；⻄东 ⼀作：东⻄)</li><li>妃嫔媵嫱，王⼦皇孙，辞楼下殿，辇来于秦。朝歌夜弦，为秦宫⼈。明星荧荧，开妆镜也；绿云 扰扰，梳晓鬟也；渭流涨腻，弃脂⽔也；烟斜雾横，焚椒兰也。雷霆乍惊，宫⻋过也；辘辘远听，杳<br> 不知其所之也。⼀肌⼀容，尽态极妍，缦⽴远视，⽽望幸焉。有不⻅者三⼗六年。燕赵之收藏，韩魏 之经营，⻬楚之精英，⼏世⼏年，剽掠其⼈，倚叠如⼭。⼀旦不能有，输来其间。鼎铛⽟⽯，⾦块珠<br> 砾，弃掷逦迤，秦⼈视之，亦不甚惜。(有不⻅者 ⼀作：有不得⻅者)嗟乎！⼀⼈之⼼，千万⼈之⼼也。秦爱纷奢，⼈亦念其家。奈何取之尽锱铢，⽤之如泥沙？使负<br> 栋之柱，多于南亩之农夫；架梁之椽，多于机上之⼯⼥；钉头磷磷，多于在庾之粟粒；瓦缝参差，多<br> 于周身之帛缕；直栏横槛，多于九⼟之城郭；管弦呕哑，多于市⼈之⾔语。使天下之⼈，不敢⾔⽽敢 怒。独夫之⼼，⽇益骄固。戍卒叫，函⾕举，楚⼈⼀炬，可怜焦⼟！</li><li>呜呼！灭六国者六国也，⾮秦也；族秦者秦也，⾮天下也。嗟乎！使六国各爱其⼈，则⾜以拒 秦；使秦复爱六国之⼈，则递三世可⾄万世⽽为君，谁得⽽族灭也？秦⼈不暇⾃哀，⽽后⼈哀之；后<br> ⼈哀之⽽不鉴之，亦使后⼈⽽复哀后⼈也。</li></ul><h2 id="文章翻译" tabindex="-1"><a class="header-anchor" href="#文章翻译" aria-hidden="true">#</a> 文章翻译</h2><ul><li>六国覆灭，天下统一。四川山林中的树木被砍伐一空，阿房宫殿得以建成。（它）覆盖了三百多里地，几乎遮蔽了天日。从骊山的北面建起，曲折地向西延伸，一直通到咸阳。渭水和樊川，浩浩荡荡地流进了宫墙。五步一座高楼，十步一座亭阁；长廊如带，迂回曲折，屋檐高挑，象鸟喙一样在半空飞啄。这些亭台楼阁啊，各自凭借不同的地势，参差环抱，回廊环绕象钩心，飞檐高耸象斗角。弯弯转转，曲折回环，象蜂房那样密集，如水涡那样套连，巍巍峨峨，不知道它们有几千万座。那长桥卧在水面上（象蛟龙），（可是）没有一点云彩，怎么会有蛟龙飞腾？那楼阁之间的通道架在半空（象彩虹），（可是）并非雨过天晴，怎么会有虹霓产生？高高低低的楼阁，幽冥迷离，使人辨不清南北西东。高台上传来歌声，使人感到暖意，如同春天一般温暖；大殿里舞袖飘拂，使人感到寒气，仿佛风雨交加那样凄冷。就在同一天内，同一座宫里，而气候冷暖却截然不同。</li><li>（六国的）宫女妃嫔、诸侯王族的女儿孙女，辞别了故国的宫殿阁楼，乘坐辇车来到秦国。（她们）早上唱歌，晚上弹琴，成为秦皇的宫人。（清晨）只见星光闪烁，（原来是她们）打开了梳妆的明镜；又见乌云纷纷扰扰，（原来是她们）一早在梳理发鬓；渭水泛起一层油腻，（是她们）泼下的脂粉水呀；轻烟缭绕，香雾弥漫，是她们焚烧的椒兰异香。忽然雷霆般的响声震天，（原来是）宫车从这里驰过；辘辘的车轮声渐听渐远，不知它驶向何方。（宫女们）极力显示自己的妩媚娇妍，每一处肌肤，每一种姿态，都极为动人。（她们）久久地伫立着，眺望着，希望皇帝能宠幸光临；（可怜）有的人三十六年始终未曾见过皇帝的身影。燕国赵国收藏的奇珍，韩国魏国聚敛的金银，齐国楚国保存的瑰宝，都是多少年、多少代，从人民手中掠夺来的，堆积如山。一旦国家破亡，不能再占有，都运送到阿房宫中。（从此）宝鼎（看作）铁锅，宝玉（看作）石头，黄金（当成）土块，珍珠（当作）砂砾，乱丢乱扔，秦人看着，也不觉得可惜。<br> 唉！一个人所想的，也是千万人所想的。秦始皇喜欢繁华奢侈，老百姓也眷念着自己的家。为什么搜刮财宝时连一分一厘也不放过，挥霍起来却把它当作泥沙一样呢？甚至使得（阿房宫）支承大梁的柱子，比田里的农夫还要多；架在屋梁上的椽子，比织机上的织女还要多；参差不齐的瓦缝，比人们身上穿的丝缕还要多；直的栏杆，横的门槛，比九州的城廊还要多；琴声笛声，嘈杂一片，比闹市里的人声还要喧闹。（这）使天下人们口里虽不敢说，但心里却充满了愤怒。秦始皇这暴君的心却日益骄横顽固。于是陈胜吴广揭竿而起，刘邦攻破函谷关；项羽放了一把大火，可惜那豪华的宫殿就变成了一片焦土！</li><li>唉！灭六国的是六国自己，不是秦国。灭秦国的是秦王自己，不是天下的人民。唉！如果六国的国君能各自爱抚自己的百姓，就足以抵抗秦国了；（秦统一后）如果也能爱惜六国的百姓，那就可以传位到三世以至传到万世做皇帝，谁能够灭亡他呢？秦国的统治者来不及为自己的灭亡而哀叹，却使后代人为它哀叹；如果后代人哀叹它而不引以为鉴，那么又要让更后的人来哀叹他们了。</li></ul>',4),c=[t];function o(_,n){return r(),i("div",null,c)}const h=e(l,[["render",o],["__file","阿房宫赋.html.vue"]]);export{h as default};
